            {
                if (!flag)
                    SqlString += "SET ";
                else SqlString += ", ";
                SqlString += "User_Pass='" + User_Pass + "'";
                flag = true;
            }
            if (!((User_Email == "") || (User_Email == null)))
            {
                if (!flag)
                    SqlString += "SET ";
                else SqlString += ", ";
                SqlString += "User_Email='" + User_Email + "'";
                flag = true;
