﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;

namespace BL
{
    class Song
    {
        public static string BL_InsertSong(
            int Song_ID,
            string Song_Name,
            int Album_ID,
            int Artist_ID,
            string Song_Lyrics,
            string Song_Clip,
            DateTime Song_Length,
            string Song_Genre,
            string Song_Pic
            )
        {
            string ErrorString="";
            if (DAL.tblSong.IsSongInDB(Song_ID) == true)
                ErrorString += "Song_ID:    this song ID is already in the data base\n";
            else if ( (Song_Name == "") || (Song_Name == null) )
                ErrorString += "Song_Name:  you haven't inserted a song name\n";
            else if (DAL.tblAlbum.IsAlbumInDB(Album_ID) == true)
                ErrorString += "Album_ID:   this album ID is already in the data base\n";
            else if (DAL.tblArtist.IsArtistInDB(Artist_ID) == true)
                ErrorString += "Artist_ID:   this artist ID is already in the data base\n";
            //if (IsWebAdress() == false)
            //    ErrorString += "Artist_ID:   this artist ID is already in the data base\n";
            else
            {
                DAL.tblSong.InsertSong(Song_ID, Song_Name, Album_ID, Artist_ID, Song_Lyrics, Song_Clip, Song_Length, Song_Genre, Song_Pic);
                ErrorString += "OK\n";
            }
            return ErrorString;
        }
        public static void Main()
        {
            BL_InsertSong(4, "The KKK Took My Baby Away", 1, 1, "ss", "as", new DateTime(), "Rock", "aa");
        }

    }
}

﻿using System;
using System.Collections.Generic;
using System.Text;
using System.Data;
using System.Data.SqlClient;

namespace BL
{
    /// <summary>
    /// In songs page, all the details about the song
    /// </summary>
    public class SongPage
    {

        public int Song_ID;
        public int Song_Pop;
        public int Album_ID;
        public int Artist_ID;
        public string Song_Name;
        public string Album_Name;
        public string Artist_Name;
        public string Song_Lyrics;
        public string Song_Clip;
        public string Song_Genre;
        public string Song_Pic;
        public DateTime Song_Length;

        public void getSongData(int Song_ID1)
        {
            DataSet DS = new DataSet();
            DataTable DT = DAL.tblSong.GetSongDT(Song_ID1);
            DS.Tables.Add(DT);

            Song_ID = Song_ID1;
            Song_Pop  = int.Parse(DS.Tables[0].Rows[0]["Song_Pop"].ToString());
            Album_ID  = int.Parse(DS.Tables[0].Rows[0]["Album_ID"].ToString());
            Artist_ID = int.Parse(DS.Tables[0].Rows[0]["Artist_ID"].ToString());
            Song_Name = DS.Tables[0].Rows[0]["Song_Name"].ToString();
            Album_Name = DAL.tblAlbum.GetAlbumName(Album_ID);
            Artist_Name = DAL.tblArtist.GetArtistName(Artist_ID);
            Song_Lyrics = DS.Tables[0].Rows[0]["Song_Lyrics"].ToString();
            Song_Clip = DS.Tables[0].Rows[0]["Song_Clip"].ToString();
            Song_Genre = DS.Tables[0].Rows[0]["Song_Genre"].ToString();
            Song_Pic = DS.Tables[0].Rows[0]["Song_Pic"].ToString();
            Song_Length = (DateTime)DS.Tables[0].Rows[0]["Song_Length"];

        }
    }
}

